#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[N], dp[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
            dp[i] = 1;
        }
        long long ans = 1;
        for (int i = 1; i < N; i++) {
            if (arr[i-1] <= arr[i]) {
                dp[i] += dp[i-1];
            }
            ans += dp[i];
        }
        printf("%lld\n", ans);
    }
    return 0;
}

