import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            int[] dp = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
                dp[i] = 1;
            }
            long ans = 1;
            for (int i = 1; i < N; i++) {
                if (arr[i-1] <= arr[i]) {
                    dp[i] += dp[i-1];
                }
                ans += dp[i];
            }
            System.out.println(ans);
        }
    }
}

