const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const arr = readline().split(' ').map(Number);
    const dp = new Array(N).fill(1);
    let ans = 1;
    for (let j = 1; j < N; j++) {
        if (arr[j-1] <= arr[j]) {
            dp[j] += dp[j-1];
        }
        ans += dp[j];
    }
    console.log(ans);
}
